from dataclasses import dataclass
from typing import List

@dataclass
class Record:
    name: str
    age: int
    salary: float

def compute_average_salary(records: List[Record]) -> float:
    total_salary = sum(record.salary for record in records)
    return total_salary / len(records) if records else 0.0

def filter_by_age(records: List[Record], min_age: int) -> List[Record]:
    return [record for record in records if record.age >= min_age]

def main() -> None:
    records = [
        Record(name="Alice", age=30, salary=70000.0),
        Record(name="Bob", age=25, salary=50000.0),
        Record(name="Charlie", age=35, salary=120000.0)
    ]

    average_salary = compute_average_salary(records)
    print(f"Average Salary: {average_salary}")

    filtered_records = filter_by_age(records, 30)
    for record in filtered_records:
        print(f"Name: {record.name}, Age: {record.age}, Salary: {record.salary}")

if __name__ == "__main__":
    main()
